package com.chrisb97.warehouse.controller;
import javafx.fxml.FXML;import javafx.fxml.FXMLLoader;import javafx.scene.Node;import javafx.scene.layout.StackPane;import java.io.IOException;
public class MainController{@FXML private StackPane contentPane;@FXML public void initialize(){show("dashboard-view.fxml");}@FXML private void showDashboard(){show("dashboard-view.fxml");}@FXML private void showProducts(){show("products-view.fxml");}@FXML private void showLocations(){show("locations-view.fxml");}@FXML private void showStock(){show("stock-view.fxml");}@FXML private void showMovements(){show("movements-view.fxml");}@FXML private void showPicking(){show("picking-view.fxml");}@FXML private void showSettings(){show("settings-view.fxml");}private void show(String file){try{Node node=FXMLLoader.load(getClass().getResource("/fxml/"+file));contentPane.getChildren().setAll(node);}catch(IOException e){throw new IllegalStateException("Could not load "+file,e);}}}
